// MARK: - Biometric Auth

enum BiometricAuthResult {
    case success
    case failed(message: String)
    case fallbackToPassword(message: String)
    case unavailable(message: String)
    case cancelled
}

final class BiometricAuthManager {
    static let shared = BiometricAuthManager()
    private init() {}

    func authenticate(reason: String, completion: @escaping (BiometricAuthResult) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Cancel"
        context.localizedFallbackTitle = "Use Password"

        var error: NSError?
        let policy: LAPolicy = .deviceOwnerAuthenticationWithBiometrics

        guard context.canEvaluatePolicy(policy, error: &error) else {
            let msg = (error?.localizedDescription).flatMap { $0.isEmpty ? nil : $0 } ?? "Biometric authentication is not available."
            completion(.unavailable(message: msg))
            return
        }

        context.evaluatePolicy(policy, localizedReason: reason) { success, evalError in
            DispatchQueue.main.async {
                if success {
                    completion(.success)
                    return
                }

                guard let laError = evalError as? LAError else {
                    completion(.failed(message: "Authentication failed. Please try again."))
                    return
                }

                switch laError.code {
                case .userCancel, .systemCancel, .appCancel:
                    completion(.cancelled)

                case .userFallback:
                    completion(.fallbackToPassword(message: "Enter your password to continue."))

                case .authenticationFailed:
                    completion(.failed(message: "We couldn’t verify your identity. Please try again or use your password."))

                case .biometryLockout:
                    completion(.fallbackToPassword(message: "Biometrics are locked due to too many failed attempts. Please enter your password."))

                case .biometryNotAvailable:
                    completion(.unavailable(message: "Biometric authentication is not available on this device."))

                case .biometryNotEnrolled:
                    completion(.unavailable(message: "No biometrics are enrolled. Please set up Face ID / Touch ID in Settings."))

                default:
                    completion(.failed(message: laError.localizedDescription))
                }
            }
        }
    }
}

